// TODO(michael): rewrite in your voice
const thesis = {
  claim:  "Philosophical debate can be systematized.",
  method: "Extract first principles, represent them as a graph, and automatically surface contradictions between them.",
  role:   "A Kim/Codex for the operator-philosopher.",
};
export default thesis;

// TODO(michael): rewrite in your voice; keep under 240 words
const methodology = [
  "Theseus extracts first principles from discussions, uploaded essays, and interviews using a language model fine-tuned on Michael's own working corpus. Each principle is stored with its provenance — the source text and the moment of extraction.",
  "Principles are linked into a graph of supports and tensions. A second model — Noosphere — walks this graph at intervals, flagging contradictions, asking refining questions, and proposing edits to bring sibling principles into coherence.",
  "The system is not a chatbot. It is a slow, structured collaborator for the operator-philosopher who wants to know, at any given moment, where their stated commitments contradict themselves.",
];
export default methodology;

// Seed dataset. TODO(michael): replace with the real principle set
// extracted from thesescodex.com once the API is available.

export type Principle = {
  id: string;          // P-014
  text: string;
  supports: string[];  // ids it supports
  tensions: string[];  // ids it tenses with
};

const principles: Principle[] = [
  { id: "P-001", text: "Knowledge is provisional; revision is a feature, not a flaw.", supports: ["P-002","P-022"], tensions: [] },
  { id: "P-002", text: "Evidence is weighed, not counted.", supports: ["P-014"], tensions: [] },
  { id: "P-014", text: "Autonomy is prior to welfare.", supports: ["P-015"], tensions: ["P-071"] },
  { id: "P-015", text: "Consent is the operator of legitimacy.", supports: [], tensions: ["P-071"] },
  { id: "P-022", text: "Preferences over outcomes are revealed through choice under constraint.", supports: ["P-002"], tensions: ["P-031"] },
  { id: "P-031", text: "Stated preferences and revealed preferences diverge predictably.", supports: [], tensions: ["P-022"] },
  { id: "P-040", text: "Power flows toward whatever is measured.", supports: ["P-052"], tensions: [] },
  { id: "P-052", text: "Metrics, once made consequential, cease to be informative.", supports: [], tensions: [] },
  { id: "P-061", text: "Institutions outlive the problems they were designed to solve.", supports: ["P-070"], tensions: [] },
